func solve(nums []int64, queries [][]int64) []int64 {
    ans := make([]int64, len(queries))

    for i, query := range queries {
        l, r, threshold := query[0], query[1], query[2]
        subarray := nums[l : r+1]
        freq := make(map[int64]int64)

        for _, num := range subarray {
            freq[num]++
        }

        var candidates []int64
        for num, count := range freq {
            if count >= threshold {
                candidates = append(candidates, num)
            }
        }

        if len(candidates) == 0 {
            ans[i] = -1
            continue
        }

        maxCount := int64(0)
        for _, num := range candidates {
            if freq[num] > maxCount {
                maxCount = freq[num]
            }
        }

        var finalCandidates []int64
        for _, num := range candidates {
            if freq[num] == maxCount {
                finalCandidates = append(finalCandidates, num)
            }
        }

        minNum := finalCandidates[0]
        for _, num := range finalCandidates {
            if num < minNum {
                minNum = num
            }
        }

        ans[i] = minNum
    }

    return ans
}
